class InvalidScoreError(Exception):
    pass

def check_score(score):
    if score < 0 or score > 100:
        raise InvalidScoreError(f'分数 {score} 不合法')
    print(f'分数合法：{score}')

check_score(85)
try:
    check_score(120)
except InvalidScoreError as e:
    print(f'捕获到异常：{e}')

